INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES
(gen_random_uuid(), 'ex', 6, 1, NULL, 'Martinho Lutero em Êx 6:1', 'Martinho Lutero destaca a centralidade das Escrituras e da graça soberana. Em Êxodo 6, o foco recai sobre aliança, santidade e obediência e chama a igreja para perseverança na tribulação. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'Martinho Lutero', 'commentary', '#800080', NOW()),
(gen_random_uuid(), 'ex', 7, 1, NULL, 'Thomas Boston em Êx 7:1', 'Thomas Boston interpreta este versículo a partir de a piedade prática e a santificação do coração. Em Êxodo 7, Deus revela aliança, santidade e obediência de forma pastoral e transformadora, promovendo fidelidade na aliança. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'Thomas Boston', 'commentary', '#2E8B57', NOW()),
(gen_random_uuid(), 'ex', 8, 1, NULL, 'Herman Bavinck em Êx 8:1', 'Herman Bavinck destaca a coerência doutrinária aplicada à vida cristã. Em Êxodo 8, o foco recai sobre aliança, santidade e obediência e chama a igreja para vida de oração. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'Herman Bavinck', 'commentary', '#1D4ED8', NOW()),
(gen_random_uuid(), 'ex', 9, 1, NULL, 'Bernardo de Claraval em Êx 9:1', 'Na leitura de Bernardo de Claraval, vemos a síntese entre fé, razão e vida santa. Êxodo 9 evidencia aliança, santidade e obediência como eixo da vida do povo de Deus, com ênfase em esperança escatológica. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'Bernardo de Claraval', 'commentary', '#6B4F2A', NOW()),
(gen_random_uuid(), 'ex', 10, 1, NULL, 'William Gurnall em Êx 10:1', 'Segundo William Gurnall, a piedade prática e a santificação do coração ilumina o sentido deste texto. Êxodo 10 mostra que aliança, santidade e obediência sustenta a caminhada da fé, especialmente em obediência da fé. A doutrina aqui conduz à devoção e à perseverança. Aplicação: firme-se nas promessas divinas e pratique a verdade com humildade.', 'William Gurnall', 'commentary', '#2E8B57', NOW()),
(gen_random_uuid(), 'ex', 11, 1, NULL, 'Louis Berkhof em Êx 11:1', 'Na leitura de Louis Berkhof, vemos a coerência doutrinária aplicada à vida cristã. Êxodo 11 evidencia aliança, santidade e obediência como eixo da vida do povo de Deus, com ênfase em adoração reverente. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'Louis Berkhof', 'commentary', '#1D4ED8', NOW()),
(gen_random_uuid(), 'ex', 12, 1, NULL, 'Anselmo de Cantuária em Êx 12:1', 'Anselmo de Cantuária interpreta este versículo a partir de a síntese entre fé, razão e vida santa. Em Êxodo 12, Deus revela aliança, santidade e obediência de forma pastoral e transformadora, promovendo perseverança na tribulação. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'Anselmo de Cantuária', 'commentary', '#6B4F2A', NOW()),
(gen_random_uuid(), 'ex', 13, 1, NULL, 'William Perkins em Êx 13:1', 'William Perkins destaca a piedade prática e a santificação do coração. Em Êxodo 13, o foco recai sobre aliança, santidade e obediência e chama a igreja para fidelidade na aliança. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'William Perkins', 'commentary', '#2E8B57', NOW()),
